import csv
from datetime import datetime

# Count records per day in October, grouped by week
week_data = {}
with open('datasets/weekly_sales_2023_oct.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        d = row['Sale_Date']
        if d.startswith('2023-10'):
            dt = datetime.strptime(d, '%Y-%m-%d')
            iso = dt.isocalendar()
            wk = f'W{iso[1]}'
            if wk not in week_data:
                week_data[wk] = []
            week_data[wk].append(d)

for wk in sorted(week_data.keys()):
    records = week_data[wk]
    print(f'{wk} ({len(records)} records): {sorted(set(records))}')
